# migration/facade.py
import hashlib
from dataclasses import dataclass
from enum import Enum
from typing import Protocol


class MigrationPhase(str, Enum):
    SHADOW = "shadow"       # AI runs silently; legacy response served
    CANARY = "canary"       # Small % routed to AI
    GRADUATED = "graduated" # Most traffic on AI; legacy is fallback
    COMPLETE = "complete"   # All traffic on AI; legacy retired


@dataclass(frozen=True)
class MigrationConfig:
    phase: MigrationPhase
    ai_traffic_pct: float   # 0.0–100.0; ignored in SHADOW and COMPLETE
    feature_name: str


class Handler(Protocol):
    async def handle(self, request: dict) -> str: ...


class MigrationFacade:
    """Routes requests between legacy and AI handlers based on migration config."""

    def __init__(
        self,
        config: MigrationConfig,
        legacy: Handler,
        ai_handler: Handler,
        metrics,  # any object with .record(name, value, tags) method
    ):
        self._config = config
        self._legacy = legacy
        self._ai = ai_handler
        self._metrics = metrics

    def _route_to_ai(self, request_id: str) -> bool:
        """Deterministic routing by request_id hash — same request always routes the same way."""
        bucket = int(hashlib.md5(request_id.encode()).hexdigest(), 16) % 100
        return bucket < self._config.ai_traffic_pct

    async def handle(self, request: dict) -> str:
        phase = self._config.phase
        request_id = request.get("request_id", "")

        if phase == MigrationPhase.SHADOW:
            # Run AI silently; return legacy response
            legacy_resp = await self._legacy.handle(request)
            try:
                ai_resp = await self._ai.handle(request)
                self._metrics.record("shadow_comparison", {
                    "feature": self._config.feature_name,
                    "match": ai_resp == legacy_resp,
                })
            except Exception as e:
                self._metrics.record("shadow_ai_error", {
                    "feature": self._config.feature_name,
                    "error": type(e).__name__,
                })
            return legacy_resp

        elif phase == MigrationPhase.COMPLETE:
            return await self._ai.handle(request)

        else:  # CANARY or GRADUATED
            use_ai = self._route_to_ai(request_id)
            handler = self._ai if use_ai else self._legacy
            handler_name = "ai" if use_ai else "legacy"

            try:
                result = await handler.handle(request)
                self._metrics.record("migration_request", {
                    "feature": self._config.feature_name,
                    "phase": phase.value,
                    "handler": handler_name,
                    "status": "ok",
                })
                return result
            except Exception as e:
                # On AI error during canary/graduated, fall back to legacy
                if use_ai:
                    self._metrics.record("migration_ai_fallback", {
                        "feature": self._config.feature_name,
                        "error": type(e).__name__,
                    })
                    return await self._legacy.handle(request)
                raise

# config/migration_state.py — stored in Redis or a config DB, not source code
MIGRATION_CONFIG = {
    "query_handler": {
        "phase": "canary",          # change this to "shadow" to instant rollback
        "ai_traffic_pct": 5.0,
        "updated_at": "2026-07-01T23:00:00Z",
        "updated_by": "ai-platform-team",
    }
}

# The facade reads this at request time (with a short TTL cache)
# Changing "phase" to "shadow" routes 100% traffic to legacy within 30s
# No code deploy required
